	})
	const data = await result.json()
}

const getSingleListing = async (id, setter) => {
	const result = await fetch(`http://localhost:5001/shop/listing/${id}`)
	const data = await result.json()
	console.log(data)
	setter(() => data)
}

const registerUser = async (userData) => {
	const result = await fetch('http://localhost:5001/register', {
		method:'POST',
		body:JSON.stringify(userData),
		headers:{'Content-type':'application/json'}
	})
	const data = await result.json()
	console.log(data)
}

const loginUser = async (userData) => {
	const result = await fetch('http://localhost:5001/login', {
		method:'POST',
		body:JSON.stringify(userData),
		headers:{'Content-type':'application/json'}
	})
	const data = await result.json()
	localStorage.setItem('isAuth', data.isAuth)
	localStorage.setItem('token', data.token)
	localStorage.setItem('cjeck', 'dddd')
}

